1754→    void moveOrCopyMessageSynchronous(Account account, long srcFolderId, List<LocalMessage> inMessages,
1755→            long destFolderId, MoveOrCopyFlavor operation) {
1756→
1757→        try {
1758→            LocalStore localStore = localStoreProvider.getInstance(account);
1759→            if ((operation == MoveOrCopyFlavor.MOVE || operation == MoveOrCopyFlavor.MOVE_AND_MARK_AS_READ)
1760→                    && !isMoveCapable(account)) {
1761→                return;
1762→            }
1763→            if (operation == MoveOrCopyFlavor.COPY && !isCopyCapable(account)) {
1764→                return;
1765→            }
1766→
1767→            LocalFolder localSrcFolder = localStore.getFolder(srcFolderId);
1768→            localSrcFolder.open();
1769→
1770→            LocalFolder localDestFolder = localStore.getFolder(destFolderId);
1771→            localDestFolder.open();
1772→
1773→            boolean unreadCountAffected = false;
1774→            List<String> uids = new LinkedList<>();
1775→            for (Message message : inMessages) {
1776→                String uid = message.getUid();
1777→                if (!uid.startsWith(K9.LOCAL_UID_PREFIX)) {
1778→                    uids.add(uid);
1779→                }
1780→
1781→                if (!unreadCountAffected && !message.isSet(Flag.SEEN)) {
1782→                    unreadCountAffected = true;
1783→                }
1784→            }
1785→
1786→            List<LocalMessage> messages = localSrcFolder.getMessagesByUids(uids);
1787→            if (messages.size() > 0) {
1788→                Timber.i("moveOrCopyMessageSynchronous: source folder = %s, %d messages, destination folder = %s, " +
1789→                        "operation = %s", srcFolderId, messages.size(), destFolderId, operation.name());
1790→
1791→                MessageStore messageStore = messageStoreManager.getMessageStore(account);
1792→
1793→                List<Long> messageIds = new ArrayList<>();
1794→                Map<Long, String> messageIdToUidMapping = new HashMap<>();
1795→                for (LocalMessage message : messages) {
1796→                    long messageId = message.getDatabaseId();
1797→                    messageIds.add(messageId);
1798→                    messageIdToUidMapping.put(messageId, message.getUid());
1799→                }
1800→
1801→                Map<Long, Long> resultIdMapping;
1802→                if (operation == MoveOrCopyFlavor.COPY) {
1803→                    resultIdMapping = messageStore.copyMessages(messageIds, destFolderId);
1804→
1805→                    if (unreadCountAffected) {
1806→                        // If this copy operation changes the unread count in the destination
1807→                        // folder, notify the listeners.
1808→                        for (MessagingListener l : getListeners()) {
1809→                            l.folderStatusChanged(account, destFolderId);
1810→                        }
1811→                    }
1812→                } else {
1813→                    resultIdMapping = messageStore.moveMessages(messageIds, destFolderId);
1814→
1815→                    if (operation == MoveOrCopyFlavor.MOVE_AND_MARK_AS_READ) {
1816→                        Collection<Long> destinationMessageIds = resultIdMapping.values();
1817→                        messageStore.setFlag(destinationMessageIds, Flag.SEEN, true);
1818→                    }
1819→
1820→                    unsuppressMessages(account, messages);
1821→
1822→                    if (unreadCountAffected) {
1823→                        // If this move operation changes the unread count, notify the listeners
1824→                        // that the unread count changed in both the source and destination folder.
1825→                        for (MessagingListener l : getListeners()) {
1826→                            l.folderStatusChanged(account, srcFolderId);
1827→                            l.folderStatusChanged(account, destFolderId);
1828→                        }
1829→                    }
